const DataTable = ({
  name,
  dimension,
  semantic,
  usage,
}: {
  name?: string;
  dimension?: string;
  semantic?: string;
  usage?: string;
}) => {
  const [rowData, setRowData] = useState(TOKEN_DATA);
  const [searchTerm, setSearchTerm] = useState("");
  useEffect(() => {
    setRowData(
      TOKEN_DATA.filter((token) => {
        const matchName = token.name
          .toLowerCase()
          .includes((name || "").toLowerCase());
        const matchDimension =
          !dimension ||
          token.dimension.toLowerCase() === (dimension || "").toLowerCase();
        const matchSemantic =
          !semantic ||
          token.semantic.toLowerCase() === (semantic || "").toLowerCase();
        const matchUsage =
          !usage || token.usage.toLowerCase() === (usage || "").toLowerCase();

        return matchName && matchDimension && matchSemantic && matchUsage;
      }),
    );
  }, [name, dimension, semantic, usage]);

  const filteredRows = useMemo(
    () =>
      rowData.filter((row) =>
        [
          row.name,
          row.usage,
          row.dimension,
          row.semantic,
          row.defaultVariant,
        ].some((v) => v?.toLowerCase().includes(searchTerm.toLowerCase())),
      ),
    [rowData, searchTerm],
  );

  return (
    <ToastContainerStory>
      <div
        className={classNames(
          "flex",
          "flex-col",
          "border-box",
          "h-screen",
          "overflow-hidden",
          "p-l",
        )}
      >
        <div
          className={classNames(
            "flex",
            "flex-col",
            "gap-m",
            "border-box",
            "size-full",
          )}
        >
          <div className={classNames("flex", "items-center", "w-s")}>
            <TextField
              value={searchTerm}
              type="search"
              placeholder="Search all tokens"
              onChange={(e) => {
                setSearchTerm(e.target.value || "");
              }}
            />
          </div>
          <div className={classNames("flex-auto", "min-h-0", "w-full")}>
            <Table
              variant="data"
              columns={colDef}
              rowHeight={40}
              rows={filteredRows}
            />
          </div>
        </div>
      </div>
    </ToastContainerStory>
  );
};

