const CreateOption = ({ defaultValues, ...props }: StoryProps) => {
  const [options, setOptions] = useState([
    { value: "red", label: "Red" },
    { value: "green", label: "Green" },
    { value: "blue", label: "Blue" },
  ]);
  const isExistingOption = (value: string) => {
    return options.some((opt) => opt.value === value || opt.label === value);
  };
  return (
    <div
      className={classNames(
        "flex-noreset",
        "border-box",
        "p-s",
        "items-start",
      )}
      data-testid="wrapper"
      style={{ inlineSize: 300 }}
    >
      <Select.Multi
        {...props}
        onChange={(e) => {
          const newValue = e.target.value;
          if (!newValue) return;
          // if not, create the new option
          if (!isExistingOption(newValue)) {
            setOptions((opts) => [
              ...opts,
              { value: newValue, label: newValue },
            ]);
          }
        }}
        defaultValue={defaultValues}
        placeholder="Create or select colors"
      >
        {options.map((opt) => (
          <Select.Option key={opt.value} value={opt.value}>
            {opt.label}
          </Select.Option>
        ))}
        <Select.OptionCreate
          isValid={(value) => {
            return value !== "false" && !isExistingOption(value);
          }}
        />
      </Select.Multi>
    </div>
  );
};

