const Controlled = ({ onChange }: Partial<ToggleButtonProps>) => {
  const [toggled, setToggled] = useState(false);
  const ref = useRef<HTMLButtonElement>(null);

  const handleChange = (e: boolean) => {
    if (onChange) {
      onChange(e);
    }
    setToggled(e);
  };
  return (
    <ToggleButton
      ref={ref}
      label="Controlled"
      toggled={toggled}
      onChange={handleChange}
    />
  );
};

